17	export enum SignupStatus {
18	  Error = 'ERROR',
19	  Overview = 'OVERVIEW',
20	  Ineligible = 'INELIGIBLE',
21	  MainCardHolder = 'MAIN_CARDHOLDER',
22	  AdditionalCardHolder = 'ADDITIONAL_CARDHOLDER',
23	  Confirmation = 'CONFIRMATION',
24	  Processing = 'PROCESSING',
25	  Success = 'SUCCESS',
26	}
