42	export const SignUp: React.FC<SignUpProps> = ({ signUpStatus }) => {
43	  const accountResponse = useCbcGetSignupAccountInformationQuery({
44	    context: { withCastleToken: true },
45	    fetchPolicy: 'cache-and-network',
46	  });
47	
48	  const walletResponse = useGetCbcWalletIdQuery({
49	    context: { withCastleToken: true },
50	    fetchPolicy: 'network-only',
51	    errorPolicy: 'all',
52	  });
53	
54	  const [status, setStatus] = useState(signUpStatus || SignupStatus.Overview);
55	
56	  useEffect(() => {
57	    // Redirect if the customer already has wallet/s
58	    if (walletResponse?.data?.cbcGetWallet?.id) {
59	      navigateTo(Path.WALLET, { id: walletResponse.data.cbcGetWallet.id });
60	    }
61	  }, [walletResponse?.data?.cbcGetWallet?.id]);
62	
63	  useEffect(() => {
64	    if (
65	      !walletResponse.loading &&
66	      !accountResponse.loading &&
67	      (!walletResponse.data ||
68	        !accountResponse.data ||
69	        walletResponse.error ||
70	        accountResponse.error)
71	    ) {
72	      setStatus(SignupStatus.Error);
73	    }
74	  }, [
75	    walletResponse.loading,
76	    accountResponse.loading,
77	    walletResponse.data,
78	    accountResponse.data,
79	    walletResponse.error,
80	    accountResponse.error,
81	  ]);
82	
83	  if (walletResponse.loading || accountResponse.loading) {
84	    return <PageLoader data-testid={SignUpTest.Loading} />;
85	  }
86	
87	  const breadcrumbs = [
88	    { label: 'Home', path: '/' },
89	    { label: 'Cashback card', path: '/cashback' },
90	  ];
91	
92	  switch (status) {
93	    case SignupStatus.Overview:
94	      return <Onboarding setSignupStatus={setStatus} />;
95	    case SignupStatus.MainCardHolder:
96	      return <MainCardHolder setSignupStatus={setStatus} />;
97	    case SignupStatus.AdditionalCardHolder:
98	      return <AdditionalCardHolder setSignupStatus={setStatus} />;
99	    case SignupStatus.Ineligible:
100	      return <Ineligible />;
101	    case SignupStatus.Processing:
102	      return <Processing />;
103	    case SignupStatus.Confirmation:
104	      return <Confirmation setSignupStatus={setStatus} />;
105	    case SignupStatus.Success:
106	      return <Success />;
107	    case SignupStatus.Error:
108	      return (
109	        <>
110	          <PageContentHeader
111	            heading="Sign up"
112	            breadcrumbs={[...breadcrumbs, { label: 'Sign up', path: formatPath(Path.WELCOME) }]}
113	          />
114	
115	          <Container backgroundColor="primary">
116	            <Flex direction="column" width="100%">
117	              <ErrorComponent dataTestId={SignUpTest.Error} />
118	            </Flex>
119	          </Container>
120	        </>
121	      );
122	    default:
123	      return null;
124	  }
125	};
126	
127	export default SignUp;
