18	export const useSignupMainCardHolder = ({ setSignupStatus }: UseSignupMainCardHolderProps) => {
19	  const trackNewServiceMainCardholderSelected = useTrackCashbackNewServiceMainCardholderSelected();
20	
21	  const [fetchAccountInformation, { called, data, error, loading }] =
22	    useCbcGetSignupAccountInformationLazyQuery();
23	
24	  const { accountHolders } = data?.account || {};
25	
26	  const form = useForm<MainCardHolderFormInput>({
27	    defaultValues: {
28	      mainCardHolder: undefined,
29	    },
30	    mode: 'onChange',
31	    resolver: yupResolver(mainCardHolderValidationSchema),
32	  });
33	
34	  const {
35	    formState: { errors },
36	    setValue,
37	    watch,
38	    handleSubmit,
39	    reset,
40	  } = form;
41	
42	  const mainCardHolder = watch('mainCardHolder');
43	
44	  const { formData, ready, storeFormData } = useStoreSignupForm<MainCardHolderFormInput>(watch);
45	
46	  const hasRestoredFormData = useRef(false);
47	
48	  useEffect(() => {
49	    if (ready && formData?.mainCardHolder && !hasRestoredFormData.current) {
50	      hasRestoredFormData.current = true;
51	      reset({
52	        mainCardHolder: formData.mainCardHolder,
53	      });
54	    }
55	  }, [ready, formData, reset]);
56	
57	  const handleChangeMainCardHolder = (cardHolder: CardHolderInput) => {
58	    setValue('mainCardHolder', cardHolder, {
59	      shouldValidate: true,
60	    });
61	  };
62	
63	  useEffect(() => {
64	    fetchAccountInformation().then(({ data }) => {
65	      if (data?.account?.accountHolders?.length === 1) {
66	        handleChangeMainCardHolder(prepareAccountHolderInput(data?.account?.accountHolders[0]));
67	      }
68	    });
69	  }, []);
70	
71	  const handleSubmitMainCardHolder = () => {
72	    storeFormData({
73	      ...formData,
74	    });
75	
76	    trackNewServiceMainCardholderSelected();
77	
78	    setSignupStatus(SignupStatus.AdditionalCardHolder);
79	  };
80	
81	  useEffect(() => {
82	    if (error) {
83	      setSignupStatus(SignupStatus.Overview);
84	    }
85	  }, [error]);
86	
87	  return {
88	    accountHolders,
89	    errors,
90	    handleChangeMainCardHolder,
91	    handleSubmitMainCardHolder: handleSubmit(handleSubmitMainCardHolder),
92	    loading: !called || (called && (loading || !accountHolders || !ready)),
93	    mainCardHolder,
94	  };
95	};
96	
97	export default useSignupMainCardHolder;
